package controller;
import koneksi.Koneksi;import model.Pengeluaran;import java.io.*;import java.sql.*;import java.time.LocalDate;import java.util.*;import com.itextpdf.kernel.pdf.*;import com.itextpdf.layout.*;import com.itextpdf.layout.element.*;
public class PengeluaranController{public boolean simpan(Pengeluaran p)throws SQLException{String sql="INSERT INTO pengeluaran(tanggal,id_kategori_pengeluaran,nominal,keterangan,created_by) VALUES(?,?,?,?,?)";try(PreparedStatement ps=Koneksi.getConnection().prepareStatement(sql)){ps.setDate(1,p.getTanggal());ps.setInt(2,p.getIdKategoriPengeluaran());ps.setDouble(3,p.getNominal());ps.setString(4,p.getKeterangan());ps.setInt(5,p.getCreatedBy());return ps.executeUpdate()>0;}}public List<Object[]> riwayat(LocalDate a,LocalDate b,String kat)throws SQLException{List<Object[]>l=new ArrayList<>();String sql="SELECT p.id_pengeluaran,p.tanggal,k.nama_kategori,p.nominal,p.keterangan FROM pengeluaran p JOIN kategori_pengeluaran k ON k.id=p.id_kategori_pengeluaran WHERE p.tanggal BETWEEN ? AND ? AND k.nama_kategori LIKE ? ORDER BY p.tanggal DESC";try(PreparedStatement ps=Koneksi.getConnection().prepareStatement(sql)){ps.setDate(1,java.sql.Date.valueOf(a));ps.setDate(2,java.sql.Date.valueOf(b));ps.setString(3,"%"+kat+"%");try(ResultSet r=ps.executeQuery()){while(r.next())l.add(new Object[]{r.getInt(1),r.getDate(2),r.getString(3),r.getDouble(4),r.getString(5)});}}return l;}public void cetakSlipGajiPdf(File f,String nama,double nominal)throws IOException{try(PdfWriter w=new PdfWriter(f);PdfDocument pdf=new PdfDocument(w);Document d=new Document(pdf)){d.add(new Paragraph("Slip Gaji").setBold().setFontSize(18));d.add(new Paragraph("Nama: "+nama));d.add(new Paragraph("Nominal: "+util.UIUtils.rupiah(nominal)));}}}
